module RefModule(
    input D,
    input Q,
    output reg pulse
);reg D_prev;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Q or posedge dbg_halt) begin
    if (D == 1'b1 && D_prev == 1'b0) begin
        pulse <= 1'b1;
    end else begin
        pulse <= 1'b0;
    end
    D_prev <= D;
end

endmodule
